"use strict";parserFactory.register("chyoa.com",()=>new ChyoaParser);class ChyoaParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.story-map-content a.title")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.layout-content-wrapper")}extractTitleImpl(e){return e.querySelector("story-map-header h1")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"footer, div.chyoa-adzone, div.ratings, div.links"),super.removeUnwantedElementsFromContentElement(e)}removeNextAndPreviousChapterHyperlinks(){}}